import{_ as d,C as n,o as s,c as r,a2 as a,E as i}from"./chunks/framework.BnBoz4Zl.js";const l="/anjian-workbuddy-bluebook-site/assets/001_image_AkBibtRBOo.BhC3hCDh.png",o="/anjian-workbuddy-bluebook-site/assets/002_image_WdfWbMN9Do.CXrAy-F9.png",p="/anjian-workbuddy-bluebook-site/assets/003_image_NhwLbBH33o.wHZ03fSp.png",h="/anjian-workbuddy-bluebook-site/assets/004_image_MdzDbUKmlo.71E_lIja.png",b="/anjian-workbuddy-bluebook-site/assets/005_image_QASabZlKzo.CrT4IJ37.png",E="/anjian-workbuddy-bluebook-site/assets/006_asset_Um2SbSClHo.BDT1bJFP.mp4",c="/anjian-workbuddy-bluebook-site/assets/007_image_BNYQbIE2no.C8Oj3Xmm.png",g="/anjian-workbuddy-bluebook-site/assets/008_image_KXwlbyY7Oo.CXbYBYlU.png",B="/anjian-workbuddy-bluebook-site/assets/009_image_HDlMbAHGTo.Dy0eAGDG.png",q=JSON.parse('{"title":"第 24 章 如何进行多 Agent 系统设计","description":"一人公司产品宣传部实践（HyperFrames + 多 Agent）、WorkBuddy 专家团产品。本章以产品宣传片专家团的实际案例，回答：多 Agent 系统如何设计分工、如何串联产物、何时值得拆分。","frontmatter":{},"headers":[],"relativePath":"bluebook/第三篇 进阶篇：把案例变成自己的工作系统/第 24 章 如何进行多 Agent 系统设计/index.md","filePath":"bluebook/第三篇 进阶篇：把案例变成自己的工作系统/第 24 章 如何进行多 Agent 系统设计/index.md","lastUpdated":1783659790000}'),A={name:"bluebook/第三篇 进阶篇：把案例变成自己的工作系统/第 24 章 如何进行多 Agent 系统设计/index.md"};function u(m,t,_,k,f,y){const e=n("MermaidDiagram");return s(),r("div",null,[t[0]||(t[0]=a('<h1 id="第-24-章-如何进行多-agent-系统设计" tabindex="-1">第 24 章 如何进行多 Agent 系统设计 <a class="header-anchor" href="#第-24-章-如何进行多-agent-系统设计" aria-label="Permalink to &quot;第 24 章 如何进行多 Agent 系统设计&quot;">​</a></h1><p>一人公司产品宣传部实践（HyperFrames + 多 Agent）、WorkBuddy 专家团产品。本章以产品宣传片专家团的实际案例，回答：多 Agent 系统如何设计分工、如何串联产物、何时值得拆分。</p><p><img src="'+l+'" alt="" loading="lazy"></p><h2 id="单-agent-和多-agent-的真正差别" tabindex="-1">单 Agent 和多 Agent 的真正差别 <a class="header-anchor" href="#单-agent-和多-agent-的真正差别" aria-label="Permalink to &quot;单 Agent 和多 Agent 的真正差别&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>单 Agent</th><th>多 Agent</th></tr></thead><tbody><tr><td>上下文</td><td>所有信息在一个任务</td><td>角色只接收必要上下文</td></tr><tr><td>分工</td><td>一个执行体串行完成</td><td>多角色并行或接力</td></tr><tr><td>工具</td><td>同一组权限</td><td>可按角色隔离工具和权限</td></tr><tr><td>质量</td><td>自己生成、自己检查</td><td>可设置独立评审者</td></tr><tr><td>成本</td><td>较低</td><td>协调、模型和工具调用更多</td></tr><tr><td>风险</td><td>一处错误影响整体</td><td>错误可能在角色间传播</td></tr></tbody></table><p>多 Agent 的价值来自专业分工、并行、权限隔离或独立评审，不来自角色数量。</p><p><img src="'+o+'" alt="" loading="lazy"></p><h2 id="任务是否值得拆分" tabindex="-1">任务是否值得拆分 <a class="header-anchor" href="#任务是否值得拆分" aria-label="Permalink to &quot;任务是否值得拆分&quot;">​</a></h2><p>满足越多，越适合多 Agent：</p><ul><li>至少两个子任务可以独立进行；</li><li>子任务需要不同方法、资料或工具；</li><li>输出可以定义清楚的交接格式；</li><li>并行能显著缩短等待；</li><li>有明确总负责人和最终验收；</li><li>预算允许多轮调用。</li></ul><p>只改一封邮件、总结一份 PDF 或格式化一个表格，不需要专家团。</p><h2 id="案例-产品宣传片专家团" tabindex="-1">案例：产品宣传片专家团 <a class="header-anchor" href="#案例-产品宣传片专家团" aria-label="Permalink to &quot;案例：产品宣传片专家团&quot;">​</a></h2><h3 id="任务背景" tabindex="-1">任务背景 <a class="header-anchor" href="#任务背景" aria-label="Permalink to &quot;任务背景&quot;">​</a></h3><p>HyperFrames 是 HeyGen 开源的视频渲染框架（截至案例时 GitHub 17.7K Star），核心特点是对 AI Agent 友好：Agent 可以自动生成基于 HTML 的视频帧并渲染输出。产品宣传片具有相对固定的套路——无需口播和演员，主要由产品展示、概念字幕和 BGM 构成。这类任务适合 Agent 团队分工处理。</p><p><img src="'+p+'" alt="" loading="lazy"></p><h3 id="工序设计" tabindex="-1">工序设计 <a class="header-anchor" href="#工序设计" aria-label="Permalink to &quot;工序设计&quot;">​</a></h3><p>产品宣传片专家团的完整工序如下：</p>',17)),i(e,{graph:"flowchart%20TD%0A%20%20%20%20A%5B%E4%B8%BB%E7%90%86%E4%BA%BA%EF%BC%9A%E6%8E%A5%E6%94%B6%E4%BB%BB%E5%8A%A1%EF%BC%8C%E6%8B%86%E8%A7%A3%E5%AD%90%E4%BB%BB%E5%8A%A1%5D%20--%3E%20B%5BBrief%20%E8%A7%92%E8%89%B2%EF%BC%9A%E8%B0%83%E7%A0%94%E4%BA%A7%E5%93%81%EF%BC%8C%E8%BE%93%E5%87%BA%E5%86%85%E5%AE%B9%E7%AE%80%E6%8A%A5%5D%0A%20%20%20%20B%20--%3E%20C%5B%E5%88%86%E9%95%9C%E5%B8%88%EF%BC%9A%E6%8C%89%20Brief%20%E6%8B%86%E8%A7%A3%E9%95%9C%E5%A4%B4%E5%BA%8F%E5%88%97%5D%0A%20%20%20%20C%20--%3E%20D%5B%E7%B4%A0%E6%9D%90%E5%B8%88%EF%BC%9A%E7%94%9F%E6%88%90%E6%88%96%E6%8A%93%E5%8F%96%E6%AF%8F%E5%B8%A7%E6%89%80%E9%9C%80%E7%B4%A0%E6%9D%90%5D%0A%20%20%20%20C%20--%3E%20E%5B%E5%89%AA%E8%BE%91%E5%B8%88%EF%BC%9A%E6%8C%89%E5%88%86%E9%95%9C%E8%A1%A8%E5%9C%A8%20HyperFrames%20%E4%B8%AD%E9%80%90%E5%B8%A7%E6%B8%B2%E6%9F%93%5D%0A%20%20%20%20D%20--%3E%20E%0A%20%20%20%20E%20--%3E%20F%5B%E9%85%8D%E4%B9%90%E5%B8%88%EF%BC%9A%E5%88%86%E6%9E%90%E6%83%85%E7%BB%AA%E6%9B%B2%E7%BA%BF%EF%BC%8C%E7%94%9F%E6%88%90%E5%B9%B6%E9%80%89%E6%8B%A9%20BGM%5D%0A%20%20%20%20F%20--%3E%20G%5B%E4%B8%BB%E7%90%86%E4%BA%BA%EF%BC%9A%E6%95%B4%E5%90%88%E6%89%80%E6%9C%89%E4%BA%A7%E7%89%A9%EF%BC%8C%E8%BE%93%E5%87%BA%E6%88%90%E7%89%87%5D%0A"}),t[1]||(t[1]=a('<h3 id="角色契约" tabindex="-1">角色契约 <a class="header-anchor" href="#角色契约" aria-label="Permalink to &quot;角色契约&quot;">​</a></h3><table tabindex="0"><thead><tr><th>角色</th><th>输入</th><th>输出</th><th>禁止动作</th></tr></thead><tbody><tr><td>主理人</td><td>用户任务描述、素材空间</td><td>任务拆解、状态追踪、成片</td><td>不跳过子任务验收直接交付</td></tr><tr><td>Brief 角色</td><td>产品官网、介绍文档</td><td>brief.md（产品定位、核心价值、目标用户）</td><td>不直接写脚本</td></tr><tr><td>分镜师</td><td>brief.md</td><td>分镜表（时间码、画面、字幕、转场、动效）</td><td>不引入 Brief 未确认的信息</td></tr><tr><td>素材师</td><td>分镜表</td><td>产品截图、概念图、界面素材</td><td>不使用无版权来源素材</td></tr><tr><td>剪辑师</td><td>素材、分镜表</td><td>逐帧 MP4 片段</td><td>不改动分镜结构</td></tr><tr><td>配乐师</td><td>分镜表、情绪标注</td><td>BGM 候选及推荐理由</td><td>不只输出一个选项</td></tr></tbody></table><h3 id="专家团演示" tabindex="-1">专家团演示 <a class="header-anchor" href="#专家团演示" aria-label="Permalink to &quot;专家团演示&quot;">​</a></h3><p>在做产品宣传片之前，需要先把相关素材放到工作空间内。</p><div class="language-Plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">Plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>我希望你做一个产品宣传片，具体的话，是宣传腾讯的workbuddy最新的专家团，主打opc场景。当前空间下我放了一些素材，成片风格可以偏apple风格、真实软件界面。整个过程全自动</span></span></code></pre></div><p><img src="'+h+'" alt="" loading="lazy"></p><p>团长先接到任务：把&quot;做一支宣传片&quot;拆成了一串子任务：先得搞清楚 WorkBuddy 专家团到底是什么、卖给谁、核心价值是什么；再决定叙事结构、镜头数量、节奏；然后再分头去做素材、剪辑、配乐。</p><p>brief 角色先开工：去把 WorkBuddy 官网、产品介绍、专家团列表都翻了一遍，输出一份 brief ，这是什么产品、目标用户是谁、最值得放进 60 秒的几个核心点。</p><p>分镜师接着 brief 干活：把 60 秒拆成了 7 个镜头，每个镜头都细到时间码、画面、文字、转场、动效、需要的素材类型。</p><p>然后 素材师 和 剪辑师 开始干活：一个去生成 / 抓产品截图、概念图，另一个把素材按分镜表往 HyperFrames 里塞，逐镜头渲染出每一段 MP4。</p><p>最有意思的是 配乐师：它不是简单写个&quot;科技感 BGM&quot;的 prompt 完事，它会先把分镜表读一遍，研究每个镜头的情绪曲线，标好哪些地方需要鼓点卡产品 reveal、哪些地方需要降下来做留白、哪些地方需要一个 hit point 推 CTA。然后再去调用音乐模型生成候选 BGM。</p><p>最后由 团长 把所有产物整合，跑最后一道剪辑，输出成片。</p><p><img src="'+b+'" alt="" loading="lazy"></p><p>整个过程我基本就是个旁观者：偶尔在关键节点拍一下板，比如分镜要不要这么排、BGM 喜不喜欢、字幕文案要不要改。</p><p>最后出来的片子，还挺不错的。</p><p><video controls preload="metadata" src="'+E+`"></video></p><h2 id="共享产物层" tabindex="-1">共享产物层 <a class="header-anchor" href="#共享产物层" aria-label="Permalink to &quot;共享产物层&quot;">​</a></h2><p>多个 Agent 不应各自维护一份&quot;产品事实&quot;。建立单一产物路径：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>project/</span></span>
<span class="line"><span>├── brief.md                  # 产品简报（Brief 角色产出，主理人确认）</span></span>
<span class="line"><span>├── storyboard.md             # 分镜表（分镜师产出，主理人确认）</span></span>
<span class="line"><span>├── assets/                   # 素材（素材师产出）</span></span>
<span class="line"><span>│   ├── screenshots/</span></span>
<span class="line"><span>│   └── concepts/</span></span>
<span class="line"><span>├── clips/                    # 逐帧片段（剪辑师产出）</span></span>
<span class="line"><span>├── bgm/                      # BGM 候选（配乐师产出）</span></span>
<span class="line"><span>└── output/final.mp4          # 成片（主理人整合）</span></span></code></pre></div><p>下游角色只读取上游已确认的产物。角色之间不通过对话传递关键内容细节。</p><h2 id="并行与串行" tabindex="-1">并行与串行 <a class="header-anchor" href="#并行与串行" aria-label="Permalink to &quot;并行与串行&quot;">​</a></h2><p><strong>可以并行：</strong> 素材生成与剪辑准备、不同镜头段落的渲染。</p><p><strong>必须串行：</strong> Brief 确认后才写分镜、分镜确认后才生成素材、素材就绪后才剪辑、成片完成后才配乐合成。</p><p>并行计划必须标明汇合点。素材和剪辑可以并行准备，但最终合成必须等待所有素材就位。</p><h2 id="主理人的职责" tabindex="-1">主理人的职责 <a class="header-anchor" href="#主理人的职责" aria-label="Permalink to &quot;主理人的职责&quot;">​</a></h2><p>主理人（制片人）是工作流控制器：</p><ul><li>解释用户任务并维护子任务状态；</li><li>分发最小必要上下文给各角色；</li><li>检查上游产物是否满足交接格式；</li><li>决定并行、等待或重试；</li><li>在关键节点（如分镜确认、BGM 选择）请用户拍板；</li><li>汇总所有产物，执行最终合成；</li><li>对成片做一致性检查（画面、字幕、BGM 节奏是否对齐）。</li></ul><h2 id="三个必须由人确认的点" tabindex="-1">三个必须由人确认的点 <a class="header-anchor" href="#三个必须由人确认的点" aria-label="Permalink to &quot;三个必须由人确认的点&quot;">​</a></h2><ol><li><strong>Brief 确认</strong>：产品定位、目标用户、核心卖点是否准确；</li><li><strong>分镜确认</strong>：叙事结构、镜头数量、节奏是否符合预期；</li><li><strong>BGM 选择</strong>：情绪风格是否与成片调性匹配。</li></ol><p>Agent 负责生成和执行，不能替代品牌方向和风格判断。</p><h2 id="产品化路径-从自建到预置专家团" tabindex="-1">产品化路径：从自建到预置专家团 <a class="header-anchor" href="#产品化路径-从自建到预置专家团" aria-label="Permalink to &quot;产品化路径：从自建到预置专家团&quot;">​</a></h2><h3 id="自建团队" tabindex="-1">自建团队 <a class="header-anchor" href="#自建团队" aria-label="Permalink to &quot;自建团队&quot;">​</a></h3><p>将上述角色封装为一套 Skills，在 Agent 框架中自行编排。适用场景：开发者需要完全控制每个角色的提示词、工具权限和交接格式。门槛包括：定义角色职责、设计交接格式、调试并行与串行逻辑。</p><h3 id="预置专家团" tabindex="-1">预置专家团 <a class="header-anchor" href="#预置专家团" aria-label="Permalink to &quot;预置专家团&quot;">​</a></h3><p>WorkBuddy 专家团将上述分工产品化：团长负责任务拆解和分配，团员并行执行，用户只需描述任务。</p><p>创建专家团也很简单在专家-&gt;我的专家-&gt;创建专家</p><p><img src="`+c+'" alt="" loading="lazy"></p><p>就会跳转到workbuddy的对话框，根据它给定的格式即可快速创建属于自己的专家。</p><p><img src="'+g+'" alt="" loading="lazy"></p><p>当前专家团覆盖的典型场景：</p><table tabindex="0"><thead><tr><th>场景类别</th><th>代表专家团</th></tr></thead><tbody><tr><td>内容创作</td><td>产品宣传片、爆款内容创作、全域分发</td></tr><tr><td>软件研发</td><td>软件开发、代码测试</td></tr><tr><td>商业分析</td><td>深度研究、投资分析、数据分析</td></tr><tr><td>业务支持</td><td>SEO、销售、营销、财税合规、HR</td></tr><tr><td>法律合规</td><td>中文法律</td></tr></tbody></table><p><img src="'+B+`" alt="" loading="lazy"></p><h3 id="两种路径的选择" tabindex="-1">两种路径的选择 <a class="header-anchor" href="#两种路径的选择" aria-label="Permalink to &quot;两种路径的选择&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>自建 Skills</th><th>预置专家团</th></tr></thead><tbody><tr><td>适用人群</td><td>开发者，需要深度定制</td><td>一人公司，直接使用</td></tr><tr><td>上手门槛</td><td>高（需定义角色、调试流程）</td><td>低（描述任务即可）</td></tr><tr><td>灵活度</td><td>高（可修改任意环节）</td><td>中（支持自定义模型接入）</td></tr><tr><td>速度</td><td>取决于搭建时间</td><td>即开即用</td></tr></tbody></table><h2 id="质量影响因素" tabindex="-1">质量影响因素 <a class="header-anchor" href="#质量影响因素" aria-label="Permalink to &quot;质量影响因素&quot;">​</a></h2><p>成片质量主要受以下因素影响：</p><ul><li><strong>Agent 底座模型</strong>：Agent 模型的指令跟随和推理能力直接影响分镜质量和任务拆解准确性；</li><li><strong>图像生成模型</strong>：影响产品截图的清晰度和概念图的视觉质量；</li><li><strong>用户提供的素材</strong>：提前放入素材空间（图片、视频）可显著提升成片质量；</li><li><strong>浏览器工具接入</strong>：若 Agent 具备浏览器操作能力，可自动抓取官网截图和产品界面，减少人工准备。</li></ul><p>全自动方案适合快速出片（开源项目介绍视频、产品演示视频等）。对品质要求高的场景，建议以 Agent 产物为基础再做一轮人工二次剪辑。</p><h2 id="失败传播控制" tabindex="-1">失败传播控制 <a class="header-anchor" href="#失败传播控制" aria-label="Permalink to &quot;失败传播控制&quot;">​</a></h2><table tabindex="0"><thead><tr><th>角色失败</th><th>降级方式</th></tr></thead><tbody><tr><td>Brief 角色无法获取产品信息</td><td>用户补充基础信息后重试</td></tr><tr><td>素材生成失败</td><td>使用用户预置素材或标记空缺位置</td></tr><tr><td>剪辑渲染超时</td><td>交付已完成的片段和分镜表</td></tr><tr><td>BGM 生成失败</td><td>提供推荐 BGM 类型描述，由用户自选</td></tr><tr><td>主理人合成失败</td><td>交付各角色产物清单，由用户手动合成</td></tr></tbody></table><p>降级交付必须说明缺失内容，不伪装成完整成果。</p><h2 id="多-agent-任务-brief-模板" tabindex="-1">多 Agent 任务 Brief 模板 <a class="header-anchor" href="#多-agent-任务-brief-模板" aria-label="Permalink to &quot;多 Agent 任务 Brief 模板&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>目标：为 [产品名称] 制作一支 [时长] 的产品宣传片。</span></span>
<span class="line"><span>风格：[参考风格，如 Apple 风、极简风]。</span></span>
<span class="line"><span>素材：[素材空间路径或已提供的图片/视频]。</span></span>
<span class="line"><span>角色：主理人、Brief、分镜师、素材师、剪辑师、配乐师。</span></span>
<span class="line"><span>确认节点：Brief 完成后、分镜完成后、BGM 选择时，需用户确认后继续。</span></span>
<span class="line"><span>模型：Agent 模型 [指定]；图像生成模型 [指定]。</span></span>
<span class="line"><span>全自动/半自动：[说明是否需要中间节点人工介入]。</span></span></code></pre></div>`,53))])}const x=d(A,[["render",u]]);export{q as __pageData,x as default};
